def calcular_logros(ind, stats):
    ganados = []
    vals = [ind.get("economia",0), ind.get("medio_ambiente",0),
            ind.get("energia",0),  ind.get("bienestar_social",0)]
    prom = sum(vals) / 4 if vals else 0
    eco  = ind.get("economia",0)
    amb  = ind.get("medio_ambiente",0)
    ene  = ind.get("energia",0)
    bie  = ind.get("bienestar_social",0)
    correctas   = stats.get("correctas", 0)
    incorrectas = stats.get("incorrectas", 0)
    dificultad  = stats.get("dificultad", "Medio")
    puntaje     = stats.get("puntaje", 0)
    eventos_pos = stats.get("eventos_positivos", 0)
    eventos_neg = stats.get("eventos_negativos", 0)
    combo_max   = stats.get("combo_max", 0)
    estrellas_usadas = stats.get("estrellas_usadas", 0)
    estrellas_rest   = stats.get("estrellas_restantes", 0)
    partidas_total   = stats.get("partidas_total", 1)
    logros_previos   = stats.get("logros_previos", [])
    est_max_aciertos = stats.get("est_max_aciertos", 0)
    todos_turno      = stats.get("todos_turno", False)
    todos_aciertan   = stats.get("todos_aciertan", False)
    decisiones_usadas = stats.get("decisiones_usadas", [])

    # Indicadores
    if all(v >= 60 for v in vals):           ganados.append("admin_eficiente")
    if amb >= 80:                            ganados.append("ciudad_verde")
    if eco >= 75:                            ganados.append("economia_boom")
    if bie >= 80:                            ganados.append("ciudad_feliz")
    if ene >= 75:                            ganados.append("energia_sost")
    if prom >= 70:                           ganados.append("equilibrio_total")
    if all(v >= 80 for v in vals):           ganados.append("ciudad_perfecta")
    if eco >= 90:                            ganados.append("super_economia")
    if amb >= 90:                            ganados.append("eden_verde")
    if all(v >= 90 for v in vals):           ganados.append("utopia")
    # Preguntas
    if correctas >= 8:                       ganados.append("maestro_preguntas")
    if correctas == 10:                      ganados.append("perfecto")
    if incorrectas == 0:                     ganados.append("sabio")
    if correctas == 5 and incorrectas == 5:  ganados.append("precision_50")
    if combo_max >= 3:                       ganados.append("combo3")
    if combo_max >= 5:                       ganados.append("combo5")
    if stats.get("nunca_tiempo_agotado", False): ganados.append("sin_tiempo")
    if stats.get("rapido_5", False):         ganados.append("rapido")
    if stats.get("gran_recuperacion", False):ganados.append("recuperacion")
    # Supervivencia
    if stats.get("ninguno_critico", True):   ganados.append("superviviente")
    if stats.get("temerario", False):        ganados.append("temerario")
    if stats.get("resurreccion", False):     ganados.append("resurreccion")
    if dificultad == "Difícil":              ganados.append("resistente")
    if estrellas_usadas == 0:                ganados.append("sin_estrellas")
    # Estrategia
    if len(set(decisiones_usadas)) >= 8:     ganados.append("estratega")
    if stats.get("nunca_cooldown_fail", True): ganados.append("cooldown_master")
    tipos = [d.get("tipo","") for d in stats.get("decisiones_obj", [])]
    if tipos.count("economia") >= 3:         ganados.append("economista")
    if tipos.count("ambiente") >= 3:         ganados.append("ecologista")
    if tipos.count("energia") >= 3:          ganados.append("energetico")
    if tipos.count("social") >= 3:           ganados.append("social")
    if all(t in tipos for t in ["economia","ambiente","energia","social"]): ganados.append("balanceado")
    # Estrellas
    if estrellas_rest >= 50:                 ganados.append("ahorrador")
    if estrellas_usadas >= 5:                ganados.append("gastador")
    if stats.get("uso_proteccion_ciudad", 0) >= 2: ganados.append("protector")
    if stats.get("estrellas_acumuladas", 0) >= 100: ganados.append("estrella_100")
    # Rondas especiales
    if stats.get("primera_ronda_ok", False): ganados.append("primera_ronda")
    if stats.get("ultima_ronda_ok", False):  ganados.append("ultima_ronda")
    if eventos_pos >= 5:                     ganados.append("evento_positivo5")
    if eventos_neg == 0:                     ganados.append("sin_eventos_neg")
    # Dificultad
    if dificultad == "Fácil"  and puntaje > 80: ganados.append("facil_maestro")
    if dificultad == "Medio"  and puntaje > 70: ganados.append("medio_maestro")
    if dificultad == "Difícil"and puntaje > 60: ganados.append("dificil_maestro")
    if stats.get("completo_3_niveles", False): ganados.append("conquistador")
    # Grupales
    if todos_aciertan:                       ganados.append("equipo_unido")
    if est_max_aciertos >= 3:               ganados.append("lider_estrella")
    if todos_turno:                          ganados.append("rotacion_perfecta")
    # Especiales
    ganados.append("novato")
    if partidas_total >= 5:                  ganados.append("veterano")
    total_logros = len(set(logros_previos + ganados))
    if total_logros >= 25:                   ganados.append("leyenda")
    if total_logros >= 40:                   ganados.append("coleccionista")

    return list(set(ganados))


def calcular_puntaje(ind, correctas, incorrectas, logros, dificultad):
    from config import DIFICULTADES
    vals = [ind.get("economia",0), ind.get("medio_ambiente",0),
            ind.get("energia",0),  ind.get("bienestar_social",0)]
    prom = sum(vals) / 4 if vals else 0
    mult = {"Fácil": 0.8, "Medio": 1.0, "Difícil": 1.3}.get(dificultad, 1.0)
    base = int(prom * mult)
    return max(0, base + correctas * 5 - incorrectas * 3 + len(logros) * 10)
